with.prompt:
Scaffold the demo app using ONE Bash tool call only. Copy this script exactly and do not rewrite the repo name, headline, or file contents.

set -euo pipefail
REPO='{{trigger.repo}}'
APP_NAME='{{trigger.app_name}}'
HEADLINE='{{trigger.headline}}'
UI_BRIEF='{{trigger.ui_brief}}'
ROOT="/tmp/${REPO}"
BACKUP="/tmp/${REPO}-git-backup"

cd "${ROOT}"
mv .git "${BACKUP}"
rm -rf "${ROOT}"
cd /tmp
npx sv create "${REPO}" --template minimal --types ts --no-install --no-add-ons
rm -rf "${ROOT}/.git"
mv "${BACKUP}" "${ROOT}/.git"
cd "${ROOT}"
cat > .gitignore <<'EOF'
node_modules
.svelte-kit
build
EOF
cat > src/routes/+page.svelte <<'EOF'
<script lang="ts">
	const modes = ['Launch', 'Stealth', 'Broadcast'] as const;
	const metricSets = {
		Launch: [
			{ label: 'Signal Uptime', value: '99.98%', accent: 'from-amber-300 via-orange-400 to-rose-500' },
			{ label: 'Viewer Sync', value: '142 ms', accent: 'from-cyan-300 via-sky-400 to-blue-500' },
			{ label: 'Clearance Ready', value: '18 teams', accent: 'from-emerald-300 via-lime-400 to-green-500' }
		],
		Stealth: [
			{ label: 'Dark Relay', value: '12 nodes', accent: 'from-fuchsia-300 via-pink-400 to-rose-500' },
			{ label: 'Quiet Window', value: '04:20', accent: 'from-slate-200 via-slate-400 to-slate-600' },
			{ label: 'Mask Integrity', value: 'A+', accent: 'from-violet-300 via-purple-400 to-fuchsia-500' }
		],
		Broadcast: [
			{ label: 'Live Scenes', value: '7 angles', accent: 'from-yellow-300 via-amber-400 to-orange-500' },
			{ label: 'Stage Energy', value: '124%', accent: 'from-red-300 via-orange-400 to-yellow-500' },
			{ label: 'Crowd Pulse', value: '18.4k', accent: 'from-teal-300 via-cyan-400 to-sky-500' }
		]
	} as const;
	let activeMode = $state<(typeof modes)[number]>('Launch');
	let clearanceLevel = $state(72);
	function selectMode(mode: (typeof modes)[number]) {
		activeMode = mode;
		clearanceLevel = mode === 'Launch' ? 72 : mode === 'Stealth' ? 91 : 84;
	}
</script>

<svelte:head>
	<title>{{trigger.app_name}}</title>
	<meta name="description" content="{{trigger.ui_brief}}" />
</svelte:head>

<script lang="ts" module>
	export const prerender = true;
</script>

<div class="shell">
	<div class="ambient ambient-a"></div>
	<div class="ambient ambient-b"></div>
	<section class="hero">
		<p class="eyebrow">Video-ready product reveal</p>
		<h1>{{trigger.headline}}</h1>
		<p class="summary">{{trigger.ui_brief}}</p>

		<div class="mode-switch" role="tablist" aria-label="Presentation mode">
			{#each modes as mode}
				<button
					type="button"
					class:active={activeMode === mode}
					onclick={() => selectMode(mode)}
				>
					{mode}
				</button>
			{/each}
		</div>

		<div class="hero-footer">
			<div>
				<p class="foot-label">Clearance level</p>
				<div class="meter-row">
					<strong>{clearanceLevel}%</strong>
					<input type="range" min="40" max="100" bind:value={clearanceLevel} />
				</div>
			</div>
			<button class="cta" type="button">Get Clearance</button>
		</div>
	</section>

	<section class="metrics" aria-label="Key metrics">
		{#each metricSets[activeMode] as metric, index}
			<article class="card" style={`animation-delay: ${index * 120}ms`}>
				<div class={`glow bg-gradient-to-r ${metric.accent}`}></div>
				<p>{metric.label}</p>
				<h2>{metric.value}</h2>
				<span>{activeMode} mode</span>
			</article>
		{/each}
	</section>
</div>

<style>
